using Microsoft.AspNetCore.Authorization;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        // All shipments (dispatchers)
        group.MapGet("/", [Authorize(Roles = "Dispatcher")] async (ApplicationDbContext db) =>
        {
            return await db.Shipments
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => ToDto(s))
                .ToListAsync();
        });

        // Track by tracking number (any authenticated user)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(ToDto(shipment));
        });

        // My shipments (customer sees their own)
        group.MapGet("/my", async (HttpContext context, ApplicationDbContext db) =>
        {
            var email = context.User.Identity?.Name;
            var shipments = await db.Shipments
                .Where(s => s.CustomerEmail == email)
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => ToDto(s))
                .ToListAsync();
            return shipments;
        });

        // Update status (dispatchers only)
        group.MapPut("/{id}/status", [Authorize(Roles = "Dispatcher")] async (int id, StatusUpdate update, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();
            shipment.Status = update.Status;
            await db.SaveChangesAsync();
            return Results.Ok();
        });
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Status = s.Status,
        Origin = s.Origin,
        Destination = s.Destination,
        EstimatedDelivery = s.EstimatedDelivery,
        ShippedDate = s.ShippedDate,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description
    };
}

public record StatusUpdate(string Status);

