@page "/dispatch"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService
@rendermode InteractiveAuto

<PageTitle>Dispatch Dashboard</PageTitle>

<h2>Shipment Dashboard</h2>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Filter by destination or tracking #..."
           @bind="filterText" @bind:event="oninput" />
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Description</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>ETA</th>
                <th>Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td><strong>@s.TrackingNumber</strong></td>
                    <td>@s.Description</td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td>
                        <span class="badge @GetStatusBadge(s.Status)">@s.Status</span>
                    </td>
                    <td>@s.ShippedDate.ToString("MMM dd, yyyy")</td>
                    <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "N/A")</td>
                    <td>
                        <select class="form-select form-select-sm" value="@s.Status"
                                @onchange="(e) => UpdateStatus(s, e.Value?.ToString()!)">
                            <option value="Pending">Pending</option>
                            <option value="In Transit">In Transit</option>
                            <option value="Out for Delivery">Out for Delivery</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Delayed">Delayed</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Status.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(ShipmentDto shipment, string newStatus)
    {
        await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
        shipment.Status = newStatus;
    }

    private static string GetStatusBadge(string status) => status switch
    {
        "Delivered" => "bg-success",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-info",
        "Delayed" => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/tracking"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService
@rendermode InteractiveAuto

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                @if (isSearching) { <span class="spinner-border spinner-border-sm"></span> }
                Search
            </button>
        </div>
    </div>
</div>

@if (searchPerformed && trackedShipment is null)
{
    <div class="alert alert-warning">No shipment found with that tracking number.</div>
}

@if (trackedShipment is not null)
{
    <div class="card mb-4">
        <div class="card-header">
            <strong>@trackedShipment.TrackingNumber</strong> — @trackedShipment.Description
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>Status:</strong> <span class="badge @GetStatusBadge(trackedShipment.Status)">@trackedShipment.Status</span></p>
                    <p><strong>Origin:</strong> @trackedShipment.Origin</p>
                    <p><strong>Destination:</strong> @trackedShipment.Destination</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Shipped:</strong> @trackedShipment.ShippedDate.ToString("MMMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong> @(trackedShipment.EstimatedDelivery?.ToString("MMMM dd, yyyy") ?? "TBD")</p>
                </div>
            </div>
        </div>
