11. 
12. var builder = WebApplication.CreateBuilder(args);
13. 
14. // Add services to the container.
15. builder.Services.AddRazorComponents()
16.     .AddInteractiveServerComponents()
17.     .AddInteractiveWebAssemblyComponents()
18.     .AddAuthenticationStateSerialization(options => options.SerializeAllClaims = true);
19. 
20. builder.Services.AddCascadingAuthenticationState();
21. builder.Services.AddScoped<IdentityRedirectManager>();
22. builder.Services.AddScoped<AuthenticationStateProvider, IdentityRevalidatingAuthenticationStateProvider>();
23. 
24. builder.Services.AddAuthentication(options =>
25.     {
26.         options.DefaultScheme = IdentityConstants.ApplicationScheme;
27.         options.DefaultSignInScheme = IdentityConstants.ExternalScheme;
28.     })
29.     .AddIdentityCookies();
30. 
31. var connectionString = builder.Configuration.GetConnectionString("DefaultConnection") ?? throw new InvalidOperationException("Connection string 'DefaultConnection' not found.");
32. builder.Services.AddDbContext<ApplicationDbContext>(options =>
33.     options.UseSqlite(connectionString));
34. builder.Services.AddDatabaseDeveloperPageExceptionFilter();
35. 
36. builder.Services.AddIdentityCore<ApplicationUser>(options =>
37.     {
38.         options.SignIn.RequireConfirmedAccount = true;
39.         options.Stores.SchemaVersion = IdentitySchemaVersions.Version3;
40.     })
41.     .AddRoles<IdentityRole>()
42.     .AddEntityFrameworkStores<ApplicationDbContext>()
43.     .AddSignInManager()
44.     .AddDefaultTokenProviders();
45. 
46. builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();
